import { execSync } from 'child_process';
import fs from 'fs';
const W='', PREP='';
const FILES={'assets/pet-profile.js':'','includes/class-reminders.php':''};
const TOKG=process.env.GH_TOKEN, REPO=process.env.GH_REPO||'raimis079-creator/petshop-bridge';
const U=process.env.WP_USER||'', P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const AUTH='-u "'+U+':'+P+'"';
function wj(m,path,body){fs.writeFileSync('/tmp/wb.json', JSON.stringify(body));
  return execSync('curl -sk '+AUTH+' -X '+m+' -H "Content-Type: application/json" --data-binary @/tmp/wb.json "https://dev.avesa.lt/wp-json/'+path+'"',{maxBuffer:50*1024*1024,timeout:70000}).toString();}
function putB64(name,b64){const u='https://api.github.com/repos/'+REPO+'/contents/screenshots/'+name;let s='';
 for(let i=0;i<5;i++){try{const j=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+TOKG+'" "'+u+'?n='+Math.random()+'"',{maxBuffer:50*1024*1024}).toString());if(j.sha)s=j.sha;}catch(e){}
  fs.writeFileSync('/tmp/pj.json',JSON.stringify({message:'r',content:b64,...(s?{sha:s}:{})}));
  const c=execSync('curl -s -o /dev/null -w "%{http_code}" -X PUT -H "Authorization: Bearer '+TOKG+'" -d @/tmp/pj.json "'+u+'"',{maxBuffer:50*1024*1024}).toString().trim();
  if(c==='200'||c==='201')return c; execSync('sleep 2');}return 'fail';}
const o={};
try{
  const tmp='/tmp/l_rem.php'; fs.writeFileSync(tmp, Buffer.from(FILES['includes/class-reminders.php'],'base64'));
  const r=execSync('php -l '+tmp+' 2>&1').toString();
  if(!/No syntax errors/.test(r)){ o.abort='LINT '+r.slice(0,150); putB64('fix224.json',Buffer.from(JSON.stringify(o)).toString('base64')); process.exit(0);}
}catch(e){}
const mk=wj('POST','code-snippets/v1/snippets',{name:'FIX224 (temp)',code:Buffer.from(W,'base64').toString('utf8'),scope:'front-end',active:true,priority:5});
let sid; try{sid=JSON.parse(mk).id;}catch(e){}
execSync('sleep 3');
fs.writeFileSync('/tmp/payload.json', JSON.stringify({files:FILES}));
try{const r=execSync('curl -sk -X POST -H "Content-Type: application/json" --data-binary @/tmp/payload.json "https://dev.avesa.lt/?ps_dep218=Dp218x"',{maxBuffer:20*1024*1024,timeout:90000}).toString();
  o.write=r.slice(r.indexOf('{'),r.lastIndexOf('}')+1);}catch(e){o.write='ERR';}
if(sid){ try{wj('POST','code-snippets/v1/snippets/'+sid,{active:false});}catch(e){} try{execSync('curl -sk '+AUTH+' -X DELETE "https://dev.avesa.lt/wp-json/code-snippets/v1/snippets/'+sid+'"');}catch(e){} }
const mk2=wj('POST','code-snippets/v1/snippets',{name:'VIS228 (temp)',code:Buffer.from(PREP,'base64').toString('utf8'),scope:'front-end',active:true,priority:5});
let sid2; try{sid2=JSON.parse(mk2).id;}catch(e){}
execSync('sleep 3');
try{const r=execSync('curl -sk "https://dev.avesa.lt/?ps_remmig=E2eTmp9x"',{timeout:30000}).toString();o.mig=r.slice(r.indexOf('{'),r.lastIndexOf('}')+1).slice(0,300);}catch(e){o.mig='ERR';}
try{execSync('curl -sk "https://dev.avesa.lt/?ps_e2eprep=E2eTmp9x"',{timeout:40000});}catch(e){}
try{
  const { chromium } = await import('playwright');
  const browser = await chromium.launch();
  const ctx = await browser.newContext({viewport:{width:1440,height:1500}, ignoreHTTPSErrors:true});
  const page = await ctx.newPage();
  await page.goto('https://dev.avesa.lt/?ps_alogin=E2eTmp9x',{waitUntil:'networkidle',timeout:60000});
  await page.waitForTimeout(1500);
  await page.evaluate(()=>{const b=[...document.querySelectorAll('button,a')].find(x=>x.textContent.trim()==='PRIIMTI');if(b)b.click();});
  await page.waitForTimeout(3000);
  await page.evaluate(()=>{const t=document.querySelectorAll('.pspet-switch-item'); for(const x of t){ if(/Sargis/.test(x.innerText)){x.click();return;} }});
  await page.waitForTimeout(3500);
  await page.evaluate(()=>{const b=[...document.querySelectorAll('button')].find(x=>/Pridėti priminimą/.test(x.textContent));if(b)b.click();});
  await page.waitForTimeout(800);
  o.cb=await page.evaluate(()=>{const c=[...document.querySelectorAll('input[type=checkbox]')].find(x=>x.parentElement&&/automatinį priminimą/.test(x.parentElement.textContent)); return c? ('yra, checked='+c.checked):'NERA';});
  await page.evaluate(()=>{
    const sels=[...document.querySelectorAll('select')];
    sels[0].value='vet_checkup';
    const s=sels.slice(-3); s[0].value='20'; s[1].value='08'; s[2].value=String(new Date().getFullYear());
  });
  await page.evaluate(()=>{const b=[...document.querySelectorAll('button')].find(x=>/Išsaugoti priminimą/.test(x.textContent));if(b)b.click();});
  await page.waitForTimeout(4500);
  o.rem=await page.evaluate(()=>{const i=document.body.innerText.indexOf('Priminimai'); return i>=0? document.body.innerText.slice(i,i+150).replace(/\s+/g,' '):'NERA';});
  await browser.close();
}catch(e){ o.err=String(e).slice(0,250); }
try{const r=execSync('curl -sk "https://dev.avesa.lt/?ps_remchk=E2eTmp9x"',{timeout:30000}).toString();o.db=r.slice(r.indexOf('{'),r.lastIndexOf('}')+1).slice(0,200);}catch(e){}
try{execSync('curl -sk "https://dev.avesa.lt/?ps_e2eclean=E2eTmp9x"',{timeout:30000});}catch(e){}
if(sid2){ try{wj('POST','code-snippets/v1/snippets/'+sid2,{active:false});}catch(e){} try{execSync('curl -sk '+AUTH+' -X DELETE "https://dev.avesa.lt/wp-json/code-snippets/v1/snippets/'+sid2+'"');}catch(e){} }
putB64('fix224.json', Buffer.from(JSON.stringify(o)).toString('base64'));
console.log('done');
